    "snpPGSBase",
    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "SNPstats",
                name = "snpPGS",
                version = c(0,1,0),
                options = options,
                results = snpPGSResults$new(options=options),
                data = data,
                datasetId = datasetId,
