                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'none')
        }))

#' Polygenic Score (PGS)
#'
#' 
#' @param data [object Object]
#' @param snpCols One column per SNP. Dosage (0/1/2) or allele strings
#'   auto-detected per column.
#' @param responseCol Optional outcome variable. If provided, an association
#'   test between PGS and response is reported (logistic for binary, linear for
#'   continuous).
#' @param covCols Optional covariate columns. If provided, regression models
#'   (logistic and linear) are adjusted for these variables. A note listing the
#'   covariates is added to the association table.
#' @param weightingMode Controls how SNP weights are applied. 'weighted' uses
#'   effect_weight values from the loaded PGS Catalog file. 'unweighted' assigns
#'   weight 1 to every SNP regardless of the file. 'both' computes and reports
#'   both scores side by side in the summary and association tables. If no
#'   weights file is loaded, unweighted scoring is used automatically.
#' @param weightsPath Path to a PGS Catalog-format file. Lines starting with
#'   '#' are skipped automatically. Recognised columns: rsID/variant_id,
#'   effect_allele, other_allele, effect_weight/beta, chr_name/chr,
#'   chr_position/pos. Missing expected columns are hidden in output; extra
#'   columns are shown concatenated in an 'Extra fields' column.
#' @param missingStrategy Strategy for handling missing genotype values.
#'   'SNP-wise' scores each individual using only their observed SNPs and
#'   divides by that individual's observed SNP count, keeping all individuals
#'   regardless of missingness.
#' @param normalize If TRUE, divides each individual's raw score by the
#'   maximum score they could have achieved given their observed SNPs. For
#'   unweighted scoring: max = 2 × observed SNP count. For weighted scoring:
#'   max = 2 × sum of weights for observed SNPs. Individuals with missing SNPs
#'   get a per-individual maximum, so scores remain comparable across
#'   individuals with different missingness. Result is in [0, 1].
#' @param standardize If TRUE, divides the (optionally normalized) PGS by its
#'   standard deviation across all individuals. The resulting score has SD = 1,
#'   so regression coefficients represent the effect per 1-SD change in PGS.
#' @param showCoverage Show the SNP coverage summary table.
#' @param showDistPlot Show the score distribution histogram and density plot.
#' @param showPercentiles Show percentile ranks for each individual and
#'   threshold table.
#' @param percentileBreaks Comma-separated list of percentile thresholds used
#'   to partition individuals into categories (e.g. "20,40,60,80" creates five
#'   bands: <P20, P20–P40, P40–P60, P60–P80, >P80).
#' @param pgsRefCategory The percentile category used as the reference group
#'   in logistic (binary response) or linear (continuous response) regression.
#'   'lowest' uses the bottom band (<lowest threshold), 'highest' uses the top
#'   band (>highest threshold), and 'middle' uses the band containing the median
#'   of the score distribution.
#' @param showAssoc Show the PGS-response association table (requires a
#'   response variable to be selected).
#' @param filterValidSnps If TRUE, the SNP Weights table is filtered to show
#'   only SNPs that passed QC and were used in scoring. SNPs excluded due to
#'   allele mismatch, missing data, or being monomorphic are hidden.
#' @param showInteraction If TRUE, fits an interaction model between the PGS
#'   and the first selected covariate (pgs × cov1) and reports the interaction
#'   term in a dedicated table. Requires both a response variable and at least
#'   one covariate. For binary responses a logistic model is used; for
#'   continuous responses a linear model is used.
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$validationMsg} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$snpGridTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$coverageTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$summaryTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$saveScores} \tab \tab \tab \tab \tab an output \cr
#'   \code{results$percentileThreshTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$percentileTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$assocTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$interactionTable} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$distPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$stratPlot} \tab \tab \tab \tab \tab an image \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$snpGridTable$asDF}
#'
#' \code{as.data.frame(results$snpGridTable)}
#'
#' @export
snpPGS <- function(
    data,
    snpCols,
    responseCol,
    covCols,
    weightingMode = "both",
    weightsPath = "",
    missingStrategy = "SNP-wise",
    normalize = TRUE,
    standardize = FALSE,
    showCoverage = TRUE,
    showDistPlot = FALSE,
    showPercentiles = FALSE,
    percentileBreaks = "20,40,60,80,90,95",
    pgsRefCategory = "middle",
    showAssoc = FALSE,
    filterValidSnps = FALSE,
    showInteraction = FALSE) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("snpPGS requires jmvcore to be installed (restart may be required)")

    if ( ! missing(snpCols)) snpCols <- jmvcore::resolveQuo(jmvcore::enquo(snpCols))
    if ( ! missing(responseCol)) responseCol <- jmvcore::resolveQuo(jmvcore::enquo(responseCol))
    if ( ! missing(covCols)) covCols <- jmvcore::resolveQuo(jmvcore::enquo(covCols))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(snpCols), snpCols, NULL),
            `if`( ! missing(responseCol), responseCol, NULL),
            `if`( ! missing(covCols), covCols, NULL))


    options <- snpPGSOptions$new(
        snpCols = snpCols,
        responseCol = responseCol,
        covCols = covCols,
        weightingMode = weightingMode,
        weightsPath = weightsPath,
        missingStrategy = missingStrategy,
        normalize = normalize,
        standardize = standardize,
        showCoverage = showCoverage,
        showDistPlot = showDistPlot,
        showPercentiles = showPercentiles,
        percentileBreaks = percentileBreaks,
        pgsRefCategory = pgsRefCategory,
        showAssoc = showAssoc,
        filterValidSnps = filterValidSnps,
        showInteraction = showInteraction)

    analysis <- snpPGSClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

